INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('bda3966288650a85', 'AZ', '["federal"]', 'election_dates', 'Which U.S. Senate seat is on the Arizona ballot in 2026?', '["US Senate election AZ 2026","Is Mark Kelly up for reelection?","Federal statewide races 2026"]', 'There is NO regular U.S. Senate election in Arizona in 2026. Arizona''s Class 1 seat was elected in 2024, and the Class 3 seat (Mark Kelly) was elected to a full term in 2022 and is not up until 2028.', 'https://azsos.gov/elections', 'Arizona Secretary of State – Election Information', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidate and voter awareness for the 2026 cycle.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('35c66b444fd0e1e9', 'AZ', '["state"]', 'election_dates', 'Is the Governor of Arizona on the ballot in 2026?', '["2026 gubernatorial race","Is there a race for governor this cycle?","When do we elect the governor?"]', 'Yes. The Governor of Arizona serves a four-year term. Governor Katie Hobbs was elected in 2022, meaning the next gubernatorial election will be held on November 3, 2026.', 'https://www.azleg.gov/Constitution/?article=5', 'Arizona Constitution, Article V, Section 1', '2026-05-10', 'static', 'statute_citation', 'Applies to candidate and voter awareness for the 2026 cycle.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('858edeb0c008ba53', 'AZ', '["federal","state","county","judicial"]', 'voter_interaction', 'Can Independent voters vote in the Republican primary in Arizona?', '["Is Arizona a closed primary state?","Can unaffiliated voters participate in the primary?","Party registration requirements"]', 'Yes. Arizona utilizes a semi-closed primary system. Voters registered as ''Party Not Designated'' (PND / Independents) may choose to vote in either the Republican or Democratic primary by requesting that specific party''s ballot.', 'https://www.azleg.gov/ars/16/00467.htm', 'A.R.S. § 16-467(B)', '2026-05-10', 'static', 'statute_citation', 'Applies to unaffiliated/independent voters in primary elections.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('62211cc0dba9b67f', 'AZ', '["federal","state","county","judicial"]', 'voter_interaction', 'Can a registered Democrat request a Republican ballot in the primary?', '["Crossover voting rules","Can party members switch ballots?","Voting in the other party''s primary"]', 'No. While Independents may choose a ballot, voters who are officially registered with a recognized political party may ONLY vote the ballot of the party for which they are registered.', 'https://www.azleg.gov/ars/16/00467.htm', 'A.R.S. § 16-467(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to registered partisan voters.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('80ec5d0761199a8f', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the Active Early Voting List (AEVL)?', '["Permanent Early Voting List","PEVL rules","How do voters get mail ballots automatically?"]', 'Formerly known as the Permanent Early Voting List (PEVL), the AEVL allows Arizona voters to sign up to automatically receive a mail-in ballot for every election they are eligible for. The vast majority of Arizona voters use this list.', 'https://www.azleg.gov/ars/16/00544.htm', 'A.R.S. § 16-544', '2026-05-10', 'static', 'statute_citation', 'Applies to all registered voters in Arizona.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('3a1da029f312816d', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can a voter be removed from the Active Early Voting List?', '["SB 1485 AEVL purge","Losing mail ballot status","When does the state stop mailing ballots?"]', 'Yes. Following 2021 legislative reforms (SB 1485), if a voter on the AEVL fails to vote an early ballot in all elections for two consecutive election cycles, and fails to respond to a 90-day confirmation notice, they will be removed from the AEVL.', 'https://www.azleg.gov/ars/16/00544.htm', 'A.R.S. § 16-544(I)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters registered on the AEVL.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('4f2a4d4bf124324e', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What kind of ID is required to vote in person in Arizona?', '["Voter ID at the polls","Proposition 200 rules","Do I need a photo ID to vote?"]', 'Under Proposition 200, a voter must present one valid form of unexpired photo identification with their name and address (like an AZ driver''s license), OR two different forms of non-photo identification that bear the name and address (like a utility bill and bank statement).', 'https://www.azleg.gov/ars/16/00579.htm', 'A.R.S. § 16-579(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all in-person voters.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('6b0bca0a310f47c2', 'AZ', '["state","county","municipal"]', 'candidate_eligibility', 'What is Arizona''s ''Resign to Run'' law?', '["Do I have to quit my job to run for office?","Incumbent running for a different seat","Article 22 Section 18"]', 'The Arizona Constitution prohibits a salaried elected official from running for any OTHER salaried local, state, or federal office, UNLESS they are in the final year of their current term. If they are not in their final year, they must resign their current office to run.', 'https://www.azleg.gov/Constitution/?article=22', 'Arizona Constitution, Article XXII, Section 18', '2026-05-10', 'static', 'statute_citation', 'Applies to salaried incumbents seeking a new elected office.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('096635d2dee03a44', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is Proposition 211 (Voters'' Right to Know Act)?', '["Dark money disclosure rules","Prop 211 reporting","Do Super PACs have to reveal donors?"]', 'Proposition 211 requires any entity making independent campaign expenditures over $50,000 in statewide campaigns (or $25,000 for local campaigns) to publicly disclose the original source of all contributions over $5,000, severely restricting ''dark money'' shielding.', 'https://www.azcleanelections.gov/voters-right-to-know', 'Citizens Clean Elections Commission – Voters'' Right to Know', '2026-05-10', 'volatile', 'official_source_direct', 'Applies to PACs, non-profits, and entities making independent expenditures.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('17616e33e0611d1f', 'AZ', '["state"]', 'finance_ethics', 'What is the Citizens Clean Elections Act?', '["Public financing in Arizona","Clean elections vs traditional funding","How do I get state money for my campaign?"]', 'It is a voluntary public financing program for candidates running for statewide and legislative offices. Participating candidates collect a specific number of $5 qualifying contributions, reject private funding/PAC money, and in return receive a set amount of public campaign funds.', 'https://www.azleg.gov/ars/16/00940.htm', 'A.R.S. § 16-940 et seq.', '2026-05-10', 'static', 'statute_citation', 'Applies to state legislative and statewide candidates opting into public financing.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('538bc64349dcd378', 'AZ', '["state"]', 'finance_ethics', 'If I accept Clean Elections public funding, do I have to participate in debates?', '["Clean elections debate rules","Mandatory candidate debates","Public funding debate requirement"]', 'Yes. A core requirement of the Citizens Clean Elections Act is that participating candidates MUST participate in publicly sponsored debates organized by the Commission. Failure to participate can result in forfeiture of public funds and severe fines.', 'https://www.azleg.gov/ars/16/00956.htm', 'A.R.S. § 16-956(A)(2)', '2026-05-10', 'static', 'statute_citation', 'Applies to publicly funded Clean Elections candidates.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('8469303b6d7659a6', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 General Election in Arizona?', '["Election day 2026","What date is the November election?","Fall general election date"]', 'The 2026 General Election will be held on Tuesday, November 3, 2026.', 'https://www.azleg.gov/ars/16/00211.htm', 'A.R.S. § 16-211', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('efb6c5fb0d1dfffe', 'AZ', '["federal","state","county","judicial"]', 'election_dates', 'When is the 2026 Primary Election in Arizona?', '["AZ primary date 2026","When do voters vote in the primary?","Summer primary date"]', 'Following recent legislative reforms (HB 2785), the Arizona primary election is statutorily set for the first Tuesday in August. For the 2026 cycle, this is Tuesday, August 4, 2026.', 'https://www.azleg.gov/ars/16/00201.htm', 'A.R.S. § 16-201', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates on the primary ballot.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('e545c12ded98f257', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the standard voter registration deadline in Arizona?', '["When do the voter registration books close?","Registration cutoff date","Last day to register to vote"]', 'The deadline to register to vote for any primary or general election is 29 days prior to the election date.', 'https://www.azleg.gov/ars/16/00120.htm', 'A.R.S. § 16-120(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all unregistered eligible voters.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('10879f035e67e856', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can a voter register on Election Day in Arizona?', '["Same-day registration rules","Registering at the polls","Is it too late to register on election day?"]', 'No. Arizona does NOT permit same-day voter registration. A voter must be registered by the 29-day cutoff prior to the election to be eligible to cast a ballot.', 'https://www.azleg.gov/ars/16/00120.htm', 'A.R.S. § 16-120 (Context)', '2026-05-10', 'static', 'statute_citation', 'Applies to unregistered eligible voters.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('f317e6d6a06fd312', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When does the early voting period start in Arizona?', '["When do mail ballots go out?","First day of early voting","Start of the early voting window"]', 'Early voting, including the mailing of ballots to voters on the Active Early Voting List (AEVL), officially begins 27 days before the election.', 'https://www.azleg.gov/ars/16/00542.htm', 'A.R.S. § 16-542(D)', '2026-05-10', 'static', 'statute_citation', 'Applies to election administrators and campaign GOTV efforts.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('88600c00d5df2a5a', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the deadline for a voter to request a mail-in ballot if they are not on the AEVL?', '["Last day to ask for a mail ballot","Cutoff to request absentee","Mail ballot request deadline"]', 'A voter who is not on the AEVL must request an early mail-in ballot no later than 5:00 p.m. on the eleventh (11th) day preceding the election.', 'https://www.azleg.gov/ars/16/00542.htm', 'A.R.S. § 16-542(E)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters requiring mail ballots.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('386b5f53dae9e299', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the absolute deadline to return an early mail ballot?', '["Mail ballot deadline","Does postmark matter for mail ballots?","How late can a mail ballot arrive?"]', 'An early ballot must be physically received by the county recorder or dropped off at a polling place or designated drop box no later than 7:00 p.m. on Election Day. Postmarks are not accepted.', 'https://www.azleg.gov/ars/16/00548.htm', 'A.R.S. § 16-548(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all voters returning early/mail ballots.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('95dcc3b8b91b0698', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How long does a voter have to ''cure'' a missing signature on their mail ballot envelope?', '["Missing signature rules","Cure period for unsigned envelopes","Fixing a rejected mail ballot"]', 'If a voter forgets to sign the affidavit envelope entirely, the signature MUST be provided by 7:00 p.m. on Election Day to be counted. Unlike mismatched signatures, there is no post-election grace period for completely missing signatures.', 'https://www.azleg.gov/ars/16/00548.htm', 'A.R.S. § 16-548(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters whose ballot envelopes lack a signature.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('956ea545643ad26d', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How long does a voter have to ''cure'' a mismatched signature on their mail ballot envelope?', '["Signature verification cure period","Mismatched signature deadline","Fixing a rejected signature match"]', 'If the county determines the signature on the envelope does not match the voter''s registration record, the voter has up to five (5) business days AFTER the election to cure the signature and have the ballot counted.', 'https://www.azleg.gov/ars/16/00550.htm', 'A.R.S. § 16-550(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters flagged for signature mismatch.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('9a0763ea7992f0b4', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How far from the polling place entrance must campaign volunteers stay?', '["Electioneering distance rules","Where can we hold signs at the polls?","Buffer zone restrictions"]', 'Arizona enforces a 75-foot buffer zone extending from the main outside entrance of the polling place. Inside this 75-foot limit, no electioneering, handing out materials, or campaigning is allowed.', 'https://www.azleg.gov/ars/16/00515.htm', 'A.R.S. § 16-515(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaign volunteers and electioneers.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('cde0dd1049a427ec', 'AZ', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'Does Arizona hold primary or general election runoffs if no candidate gets 50%?', '["Runoff threshold","What happens in a crowded primary?","Do I need a majority to win the nomination?"]', 'No. Arizona state and federal elections do not utilize runoffs. The candidate who receives the highest number of votes (a simple plurality) wins the primary nomination or the general election, even if they do not secure a majority.', 'https://www.azleg.gov/ars/16/00645.htm', 'A.R.S. § 16-645', '2026-05-10', 'static', 'statute_citation', 'Applies to all state and federal partisan elections.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('5f978297edc63b3d', 'AZ', '["federal","state"]', 'redistricting', 'Who is responsible for drawing congressional and legislative maps in Arizona?', '["Who controls redistricting?","Legislative map drawing","Independent Redistricting Commission"]', 'Redistricting in Arizona is completely removed from the state legislature. Maps are drawn and approved by the Arizona Independent Redistricting Commission (IRC), a five-member bipartisan panel established by the state constitution.', 'https://www.azleg.gov/Constitution/?article=4', 'Arizona Constitution, Article IV, Part 2, Section 1', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates navigating district boundaries.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('fea5539e377c7ed4', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Are contribution limits adjusted for inflation in Arizona?', '["Do contribution limits go up?","Inflation adjustment for campaign limits","How often do limits change?"]', 'Yes. Arizona law requires the Secretary of State to adjust all base campaign contribution limits by $100 every odd-numbered year to account for inflation, meaning the limits incrementally increase each election cycle.', 'https://www.azleg.gov/ars/16/00912.htm', 'A.R.S. § 16-912(B)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all donors and campaigns subject to contribution limits.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('1c5aa4fc9e398bd4', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can a corporation or labor union donate directly to my campaign?', '["Are corporate contributions legal?","Can a business write a campaign check?","Corporate donation ban"]', 'No. Under Arizona law, corporations, limited liability companies that are taxed as corporations, and labor organizations are strictly prohibited from making direct contributions to candidate committees.', 'https://www.azleg.gov/ars/16/00916.htm', 'A.R.S. § 16-916(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidate campaigns and business/union entities.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('13f13ece13265383', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the maximum individual contribution limit for a state or local candidate in the 2025-2026 cycle?', '["How much can one person donate?","Maximum campaign contribution cap","Individual donor limits 2026"]', 'For the 2025-2026 election cycle, the inflation-adjusted contribution limit from an individual or standard PAC is strictly set at $6,750 per election cycle for both statewide AND legislative/local candidates.', 'https://www.azleg.gov/ars/16/00912.htm', 'A.R.S. § 16-912(B) & AZ Secretary of State Limits', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to individuals and PACs donating to state and local campaigns.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('d4b24a7db01a152e', 'AZ', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'How much is the candidate filing fee in Arizona?', '["Qualifying fee amount","How much does it cost to get on the ballot?","Cost to run for office"]', 'Arizona does NOT charge a monetary filing fee for candidates qualifying via standard nomination petitions. Access to the ballot is secured exclusively by gathering the statutorily required number of valid voter signatures.', 'https://www.azleg.gov/ars/16/00311.htm', 'A.R.S. § 16-311', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates utilizing the standard petition method.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('d41b2e62df34e07f', 'AZ', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What must I file BEFORE I start collecting petition signatures?', '["Statement of Interest rules","When can I start gathering signatures?","Form 1 requirement"]', 'A candidate MUST file a ''Statement of Interest'' with the appropriate filing officer BEFORE collecting their first nomination petition signature. Any signatures collected prior to filing this form are legally invalid and will be thrown out.', 'https://www.azleg.gov/ars/16/00311.htm', 'A.R.S. § 16-311(H)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates gathering nomination signatures.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('42ab445d4bdd7e1a', 'AZ', '["federal","state","county"]', 'ballot_access', 'How are major party petition signature requirements calculated?', '["How many signatures do I need?","Primary petition thresholds","Signature formula"]', 'Major party signature requirements are tiered based on the office and voter registration totals. For example, a U.S. Senate or statewide candidate needs signatures equal to at least 0.25% of the qualified signers of their party in the state. U.S. House and State Legislative candidates need at least 0.5% of their party''s qualified signers in the district.', 'https://www.azleg.gov/ars/16/00322.htm', 'A.R.S. § 16-322(A)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates seeking a major party nomination.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('4c08e65af0edcb03', 'AZ', '["federal","state","county"]', 'ballot_access', 'How many petition signatures does an Independent candidate need to run?', '["Independent candidate petition rules","Minor party signature threshold","Avoiding the party primary"]', 'An independent candidate requires signatures equal to at least 3% of the total number of registered voters who are NOT members of a recognized political party in the state, county, or district they are running in.', 'https://www.azleg.gov/ars/16/00341.htm', 'A.R.S. § 16-341(E)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to independent candidates seeking ballot access.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('fe4e29b5af6a5ddc', 'AZ', '["state","county","municipal","judicial"]', 'finance_ethics', 'Do I have to file a personal financial disclosure to get on the ballot?', '["Ethics paperwork for candidates","When do I file financial disclosures?","Statement of Financial Interests"]', 'Yes. A candidate for local or state office must file a Statement of Financial Interests (disclosing employer, significant investments, real property, and debts) simultaneously with their nomination papers.', 'https://www.azleg.gov/ars/38/00542.htm', 'A.R.S. § 38-542', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for state, county, and local offices.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('6f03e20b41008eb3', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When do I have to officially register my campaign committee with the state?', '["Do I need a treasurer before I raise money?","Statement of Organization timing","Committee registration threshold"]', 'A candidate must file a Statement of Organization within 10 days of receiving contributions or making expenditures (including candidate personal funds) that total a specific statutory threshold, currently adjusted to $1,500 for the 2025-2026 cycle.', 'https://www.azleg.gov/ars/16/00905.htm', 'A.R.S. § 16-905(A)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all newly formed campaign committees.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('83e3269bfb306419', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the standard campaign finance reporting schedule in an election year?', '["How often do I file finance reports?","Election code reporting cycles","When are my disclosure reports due?"]', 'Committees must file comprehensive reports covering Quarter 1, Quarter 2, a Pre-Primary Report, a Post-Primary/Quarter 3 Report, a Pre-General Report, and a Post-General/Quarter 4 Report.', 'https://www.azleg.gov/ars/16/00927.htm', 'A.R.S. § 16-927', '2026-05-10', 'static', 'statute_citation', 'Applies to all active campaign committees.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('a70391dcf1994289', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late?', '["How much are late fees for ethics reports?","Fines for missing a deadline","Secretary of State penalties"]', 'For traditional candidates, the penalty for late filing is $10 per day for the first 15 days, escalating to $25 per day thereafter. (Note: Clean Elections candidates face much steeper, separate penalties from the Commission).', 'https://www.azleg.gov/ars/16/00937.htm', 'A.R.S. § 16-937(B)', '2026-05-10', 'static', 'statute_citation', 'Applies to traditional candidates failing to file disclosure reports on time.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('a9561a3fbe936270', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'At what dollar amount do I have to list a donor''s name, address, and occupation?', '["Itemization threshold for donors","Do I need the address of a $20 donor?","Reporting small donations"]', 'A campaign must itemize the name, address, occupation, and employer of any contributor whose total aggregate contributions exceed $100 for the election cycle.', 'https://www.azleg.gov/ars/16/00901.htm', 'A.R.S. § 16-901(33)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns tracking donor data.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('ccc9a1cd66051f90', 'AZ', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'Does Arizona have a ''Sore Loser'' law preventing me from running as an independent or write-in if I lose the primary?', '["Can a primary loser run in the general?","Running as unaffiliated after losing","Sore loser prohibitions"]', 'Yes. A candidate who is defeated in a political party primary is legally prohibited from running as an independent, minor party, or write-in candidate in the subsequent general election.', 'https://www.azleg.gov/ars/16/00312.htm', 'A.R.S. § 16-312(F) & § 16-341(B)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates defeated in a partisan primary.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('f8119dde7632879a', 'AZ', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What happens if a party''s nominee dies or withdraws after the primary but before the general election?', '["Vacancy after qualifying","Replacing a dead candidate","Nominee replacement procedure"]', 'If a vacancy occurs due to death, mental incapacity, or forced disqualification after the primary, the party committee may nominate a replacement. However, if the candidate *voluntarily* withdraws after the primary, the party CANNOT replace them on the ballot.', 'https://www.azleg.gov/ars/16/00343.htm', 'A.R.S. § 16-343(F)', '2026-05-10', 'static', 'statute_citation', 'Applies to party committees attempting to fill a vacancy on the ballot.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('f71f57b56bc09074', 'AZ', '["state","county","municipal","special_district"]', 'recall_rules', 'Can an elected official be recalled from office by voters in Arizona?', '["Recall election procedures","Removing an official early","How do we recall a governor?"]', 'Yes. Every public officer in the state of Arizona, holding an elective office, either by election or appointment, is subject to recall by the qualified electors of their electoral district.', 'https://www.azleg.gov/Constitution/?article=8', 'Arizona Constitution, Article VIII, Part 1, Section 1', '2026-05-10', 'static', 'statute_citation', 'Applies to voters inquiring about recalling elected officials.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('45b0db05042e937a', 'AZ', '["state","county","municipal","special_district"]', 'recall_rules', 'How many signatures are required to trigger a recall election?', '["Recall signature threshold","Math for recall petitions","How many people need to sign?"]', 'A recall petition demands valid signatures equal in number to at least 25% of the total number of votes cast for ALL candidates for that specific office in the last preceding general election.', 'https://www.azleg.gov/Constitution/?article=8', 'Arizona Constitution, Article VIII, Part 1, Section 1', '2026-05-10', 'static', 'statute_citation', 'Applies to organizers of a recall petition.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('2667dd6deb9f9255', 'AZ', '["state"]', 'recall_rules', 'Has a state official ever been successfully recalled in Arizona?', '["Recall history","Russell Pearce recall","Does recall actually work?"]', 'Yes. Most notably, in 2011, Arizona State Senate President Russell Pearce was successfully recalled and defeated in the subsequent recall election, making him the first sitting state senate president in U.S. history to be recalled.', 'https://azsos.gov/elections', 'Arizona Secretary of State (Historical Context)', '2026-05-10', 'static', 'official_source_direct', 'Applies to organizers assessing the viability of recall efforts.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('ef41b5b8001623c0', 'AZ', '["county","municipal"]', 'election_dates', 'How is election administration divided between the state and counties?', '["Who runs the elections?","Maricopa county elections","County recorders vs Secretary of State"]', 'While the Secretary of State issues the Election Procedures Manual (EPM), Arizona''s 15 individual County Recorders and County Boards of Supervisors actually run the elections, meaning procedures can vary. Maricopa County alone contains over 60% of the state''s registered voters.', 'https://azsos.gov/elections/about-elections', 'Arizona Secretary of State – About Elections', '2026-05-10', 'static', 'official_source_direct', 'Applies to campaigns navigating regional election procedures.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('00229e3d5bc3296a', 'AZ', '["judicial"]', 'election_dates', 'Are Superior Court judges elected directly by the voters in Arizona?', '["Judicial elections","Merit selection vs direct election","How do I run for judge?"]', 'It depends on the county. In counties with populations over 250,000 (Maricopa, Pima, Pinal, Coconino), judges are appointed via ''merit selection'' and face nonpartisan retention elections. In the remaining 11 smaller counties, judges are elected directly via traditional partisan elections.', 'https://www.azleg.gov/Constitution/?article=6', 'Arizona Constitution, Article VI, Section 37 & 38', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for Superior Court.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('4410eb15ab300b2d', 'AZ', '["judicial"]', 'election_dates', 'How are Appellate and Supreme Court Justices selected?', '["Are the state supreme court justices elected?","Appellate judge elections","How to run for supreme court"]', 'Arizona Court of Appeals Judges and Supreme Court Justices are chosen strictly through the merit selection process (appointed by the Governor from a commission''s list). They never run in partisan elections, but face public Yes/No retention votes at the end of their terms.', 'https://www.azleg.gov/Constitution/?article=6', 'Arizona Constitution, Article VI, Section 38', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for higher state courts.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('3cc1bbcca5cfaf79', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Are absentee ballot drop boxes allowed in Arizona?', '["Where are the drop boxes?","Can I drop off my mail ballot?","Drop box availability rules"]', 'Yes. Arizona currently allows secure ballot drop boxes managed by the County Recorders. However, their use, security, and private monitoring are actively litigated in federal courts and heavily contested by the state legislature, making their status highly volatile.', 'https://azsos.gov/elections/about-elections/elections-procedures-manual', 'Arizona Secretary of State – Election Procedures Manual', '2026-05-10', 'volatile', 'official_source_direct', 'Applies to voters returning mail ballots and county election officials.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('9e0ac09a634774e4', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can a campaign volunteer help a voter mark their ballot inside the polling place?', '["Voter assistance rules","Who can help someone vote in the booth?","Can I help my mom vote?"]', 'Yes, but strictly regulated. A voter who requires assistance may be accompanied by a person of the voter''s own choice, OR they may request assistance from two poll workers of different political parties. An employer or union agent may NOT assist them.', 'https://www.azleg.gov/ars/16/00580.htm', 'A.R.S. § 16-580(G)', '2026-05-10', 'static', 'statute_citation', 'Applies to all voters needing assistance and volunteers providing it.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('09305b7ea4dcba5b', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Under what circumstances is a voter issued a provisional ballot?', '["Why do people vote provisionally?","What if a voter isn''t on the rolls?","Voting without an ID"]', 'A provisional ballot is issued if a voter''s name is not on the e-pollbook roster, if they cannot produce the required photo/non-photo ID, or if the roster indicates they were already mailed an early ballot but they wish to vote in person.', 'https://www.azleg.gov/ars/16/00584.htm', 'A.R.S. § 16-584(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters facing eligibility issues at the polls.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('d518411393179318', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the basic voter eligibility requirements in Arizona?', '["Who can register to vote?","Voting age and citizenship","Can out of state college students vote?"]', 'To register to vote in Arizona, an individual must be a U.S. citizen, an Arizona resident for at least 29 days preceding the election, and 18 years old by the date of the general election.', 'https://www.azleg.gov/ars/16/00101.htm', 'A.R.S. § 16-101(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all individuals seeking to register to vote.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('f9685e473a8dd3ee', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can an individual with a felony conviction vote in Arizona?', '["Felony voting rights","Can felons vote after prison?","Restoration of rights in AZ"]', 'It depends. If a person has exactly ONE felony conviction, their voting rights are automatically restored upon the completion of their sentence (including parole and payment of restitution). If they have TWO or more felony convictions, they must petition a judge to restore their rights.', 'https://www.azleg.gov/ars/13/00907.htm', 'A.R.S. § 13-907', '2026-05-10', 'static', 'statute_citation', 'Applies to Arizona residents with past felony convictions.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('a17a1701b6496ca5', 'AZ', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What happens if I want to withdraw my candidacy after I qualify?', '["How do I quit the race?","Removing my name from the ballot","Withdrawal procedures"]', 'A candidate may withdraw their candidacy by filing a formal, notarized statement of withdrawal with the filing officer. If submitted after the ballots are printed, their name remains on the ballot, but votes cast for them will not be tabulated.', 'https://www.azleg.gov/ars/16/00343.htm', 'A.R.S. § 16-343(E) & § 16-312(D)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates wishing to officially terminate their campaign.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('30f229d8c1636ae7', 'AZ', '["federal","state"]', 'redistricting', 'Are the Arizona congressional maps currently being litigated for the 2026 election?', '["Current redistricting map","Did the court change the district lines?","IRC map status"]', 'The maps certified by the Arizona Independent Redistricting Commission (IRC) in early 2022 remain the legally active boundaries for the 2026 election cycle.', 'https://azsos.gov/elections', 'Arizona Secretary of State – Election Information', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates and voters navigating district boundaries.', 'batch_2026-05-10T21-20-35_arizona_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('4528ed4e8057f5df', 'AZ', '["state","county","municipal","special_district"]', 'ballot_access', 'How many petition signatures does it take to form a newly recognized political party?', '["New party recognition threshold","Starting a third party in Arizona","Signature formula for minor parties"]', 'To qualify a new political party for statewide recognition, organizers must file a petition bearing the signatures of qualified electors equal to at least 1.33% of the total votes cast for Governor at the last preceding general election.', 'https://www.azleg.gov/ars/16/00801.htm', 'A.R.S. § 16-801(A)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to organizations seeking formal state party recognition.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('2e564f574896a5ad', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the specific deadline for a voter to request a mail-in ballot for the November 2026 General Election?', '["Last day to ask for a mail ballot in 2026","Cutoff to request absentee for the fall","2026 mail ballot request deadline"]', 'A voter must request an early mail-in ballot no later than 5:00 p.m. on the 11th day preceding the election. For the 2026 General Election, this is Friday, October 23, 2026.', 'https://www.azleg.gov/ars/16/00542.htm', 'A.R.S. § 16-542(E)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to voters requiring mail ballots for the fall election.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('f6db24c8016aa5c3', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the absolute deadline to return an early mail ballot for the November 2026 General Election?', '["Mail ballot return deadline 2026","Does postmark matter for mail ballots?","How late can a mail ballot arrive?"]', 'For the 2026 General Election, an early ballot must be physically received by the county recorder or dropped off no later than 7:00 p.m. on Tuesday, November 3, 2026. Postmarks are not accepted.', 'https://www.azleg.gov/ars/16/00548.htm', 'A.R.S. § 16-548(A)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all voters returning early/mail ballots.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('31c378fcfc07e81d', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Is Proposition 211 currently being actively enforced?', '["Are the dark money rules tied up in court?","Prop 211 litigation status","Do Super PACs actually have to reveal donors?"]', 'Yes. While Proposition 211 is the subject of ongoing constitutional litigation by conservative groups, the Citizens Clean Elections Commission actively enforces the original-source disclosure requirements for ''covered persons'' spending over the $50k/$25k thresholds.', 'https://www.azcleanelections.gov/voters-right-to-know', 'Citizens Clean Elections Commission – Voters'' Right to Know', '2026-05-10', 'volatile', 'official_source_direct', 'Applies to third-party organizations making independent expenditures.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('fa6d034d9f2bcec3', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can my campaign accept donations from foreign nationals?', '["Accepting money from non-citizens","Foreign contributions in AZ","Can someone from overseas donate?"]', 'No. Under both federal preemption and A.R.S. § 16-911, foreign nationals are strictly prohibited from making contributions, and candidate committees are strictly prohibited from knowingly accepting them.', 'https://www.azleg.gov/ars/16/00911.htm', 'A.R.S. § 16-911(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns and political committees.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('3d80e2340501e18b', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What are the disclaimer rules for campaign robocalls and texts?', '["Robocall rules","Voice call political advertising","Do auto-dialers and mass texts need to say who paid for it?"]', 'Arizona law requires that any political advertisement (including mass text messages and automated telephonic communications) clearly contain the words ''Paid for by'' followed by the name of the person or committee paying for the message.', 'https://www.azleg.gov/ars/16/00925.htm', 'A.R.S. § 16-925(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns conducting phone or SMS outreach.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('0f0c5ff0b45f26c9', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does my campaign website or digital ad require a ''Paid for by'' disclaimer?', '["Digital advertising disclaimers","Do Facebook ads need disclosures?","Website paid-for rules"]', 'Yes. Digital advertising and campaign websites are subject to the same ''Paid for by'' disclosure requirements as traditional media under A.R.S. § 16-925.', 'https://www.azleg.gov/ars/16/00925.htm', 'A.R.S. § 16-925', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns running digital advertisements.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('a34a2de82fda7233', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When can I put up campaign signs, and when do they have to come down?', '["Right-of-way signage rules","Post-election signage removal","How long can signs stay up?"]', 'Under state law, cities and counties cannot prohibit political signs in public rights-of-way during the period beginning 71 days before a primary election and ending 15 days after the general election.', 'https://www.azleg.gov/ars/16/01019.htm', 'A.R.S. § 16-1019(C)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns conducting field operations.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('f778385ad56db493', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay for legal defense?', '["Paying lawyers with donor money","Are legal fees a campaign expense?","Defending against ethics complaints"]', 'Yes, but legal fees may only be paid from campaign funds if the legal services are directly related to the campaign or the execution of the candidate''s official duties.', 'https://www.azleg.gov/ars/16/00939.htm', 'A.R.S. § 16-939(A) (Context)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates facing legal or ethics challenges.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('96697522e49fd02a', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay my personal mortgage or buy groceries?', '["Personal use of campaign funds","Can I pay rent with donor money?","Impermissible uses of campaign cash"]', 'No. Arizona law strictly dictates that campaign funds shall not be used for personal purposes. Funds must be used exclusively for influencing the outcome of an election or for expenses related to holding public office.', 'https://www.azleg.gov/ars/16/00939.htm', 'A.R.S. § 16-939(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates and officeholders.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('7c566047fa9c56b5', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I value an in-kind contribution of goods or services?', '["In-kind valuation","How much is a donated venue worth?","Reporting free services"]', 'In-kind contributions must be reported at their fair market value at the time the contribution is made. They count directly against the contributor''s per-cycle contribution limits.', 'https://www.azleg.gov/ars/16/00911.htm', 'A.R.S. § 16-911', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns accepting non-monetary donations.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('dfea504a39311d12', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is a ''bundled'' contribution and how is it reported?', '["Bundling donations","Reporting checks gathered by a fundraiser","Do bundlers count against limits?"]', 'A bundled contribution is when an intermediary collects multiple checks and delivers them. The campaign must report the actual original contributors, and the amounts count against the individuals'' limits.', 'https://azsos.gov/elections/campaign-finance-reporting', 'Arizona Secretary of State – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to campaigns utilizing fundraisers who gather checks.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('52a11c79c3350d9b', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can two candidates host a joint fundraising event and split the costs?', '["Joint fundraising rules","Sharing campaign event costs","Splitting money with another candidate"]', 'Yes. Candidates may engage in joint fundraising. Costs and contributions must be proportionally allocated and reported by the respective campaign committees so that no individual contribution limits are circumvented.', 'https://azsos.gov/elections/campaign-finance-reporting', 'Arizona Secretary of State – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to campaigns pooling resources for fundraising.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('48efe70dc90ff3bf', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When does a Political Action Committee (PAC) have to register with the state?', '["PAC registration threshold","When do independent groups have to disclose?","Threshold for third-party reporting"]', 'An entity must register as a PAC if it meets the definition of a political committee and accepts contributions or makes expenditures aggregating more than the statutory threshold (currently adjusted to $1,500).', 'https://www.azleg.gov/ars/16/00905.htm', 'A.R.S. § 16-905(B)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to PACs operating in Arizona.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('892c35dab47e72de', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is a ''Mega PAC'' and why does it have different contribution limits?', '["Mega PAC certification","Super PAC vs Mega PAC","Can a PAC give me more money?"]', 'In Arizona, a ''Mega PAC'' is a committee certified by the Secretary of State that has received at least $10 contributions from at least 500 individuals. Mega PACs are legally permitted to contribute exactly double the standard PAC limit to candidates.', 'https://www.azleg.gov/ars/16/00908.htm', 'A.R.S. § 16-908', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates receiving PAC funding.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('b4fe7d9b2268027c', 'AZ', '["state"]', 'residency', 'What are the residency and age requirements to run for Governor of Arizona?', '["How old to run for governor?","Residency rules for statewide office","Qualifications for governor"]', 'A candidate for Governor must be at least 25 years old, a U.S. citizen for 10 years, and a resident of Arizona for at least five (5) years preceding the election.', 'https://www.azleg.gov/Constitution/?article=5', 'Arizona Constitution, Article V, Section 2', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for Governor.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('1bc2f587787db0c9', 'AZ', '["state"]', 'residency', 'What are the age requirements to run for the State Legislature in Arizona?', '["How old to run for state house?","Age limit for state senate","General Assembly age rules"]', 'Candidates for both the Arizona State Senate and the State House of Representatives must be at least 25 years of age.', 'https://www.azleg.gov/Constitution/?article=4', 'Arizona Constitution, Article IV, Part 2, Section 2', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for the State Legislature.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('9ca0873ce9b48f24', 'AZ', '["state"]', 'election_dates', 'How are vacancies in the State Legislature filled?', '["Special elections for state rep","Filling an empty senate seat","What happens if a legislator resigns?"]', 'Arizona does not hold special elections for legislative vacancies. The vacancy is filled by appointment by the County Board of Supervisors, who must choose a replacement from the same political party as the departing legislator.', 'https://www.azleg.gov/ars/41/01202.htm', 'A.R.S. § 41-1202(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to the replacement of sitting legislators.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('94dcc5e11b1ca590', 'AZ', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Is Proposition 314 (Secure Border Act) an election law that changes how campaigns run?', '["Prop 314 impact on elections","Does the Secure Border Act affect voting?","Did Prop 314 change voter ID?"]', 'No. While Proposition 314 (2024) significantly altered state immigration enforcement and created high-turnout political environments, it did not alter statutory election administration, candidate qualifying, or ballot access rules.', 'https://azsos.gov/elections', 'Arizona Secretary of State (Context)', '2026-05-10', 'static', 'official_source_direct', 'Applies to campaigns navigating Arizona''s political landscape.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('c51b01af487b0416', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How long must my campaign treasurer keep our financial records?', '["Record retention rules","How long do I save receipts?","Keeping finance reports post-election"]', 'The committee treasurer must preserve all records, including bank statements and receipts, for two (2) years following the end of the election cycle to which the records pertain.', 'https://www.azleg.gov/ars/16/00904.htm', 'A.R.S. § 16-904(C)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaign treasurers.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('2100bc36fcc5cfda', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I officially close my campaign account after the election?', '["Ending my campaign reporting obligations","Filing the termination report","How to stop filing ethics reports"]', 'To terminate a committee, a candidate must file a termination statement with the filing officer certifying that they will no longer receive contributions or make expenditures, and that all surplus funds have been properly disposed of.', 'https://www.azleg.gov/ars/16/00933.htm', 'A.R.S. § 16-933(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates wishing to terminate their campaign committee.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('eac33454e4066be5', 'AZ', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What must I do with my surplus campaign funds upon termination?', '["Disposing of leftover money","Can I keep my campaign cash?","Final campaign account closure"]', 'Surplus funds may be returned pro-rata to contributors, donated to a 501(c)(3) charity, transferred to a political party committee, or retained/transferred for a future campaign for the same candidate.', 'https://www.azleg.gov/ars/16/00933.htm', 'A.R.S. § 16-933(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates distributing surplus funds.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('d9ec2899c64ef809', 'AZ', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'How and when can I legally challenge an opponent''s eligibility to run for office?', '["Candidacy challenge procedure","Proving my opponent doesn''t live in the district","Filing a protest against a candidate"]', 'Any elector may challenge a candidate''s nomination petition (including residency qualifications) by filing an action in the superior court within exactly 10 days (excluding weekends and holidays) after the last day for filing nomination papers.', 'https://www.azleg.gov/ars/16/00351.htm', 'A.R.S. § 16-351(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to individuals initiating eligibility disputes against candidates.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('0f20a024d24b2d81', 'AZ', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Can I run for Mayor and State Legislature at the same time?', '["Dual candidacy rules in Arizona","Can I run for two offices at once?","Running for multiple seats on one ballot"]', 'No. Under Arizona law, a candidate''s name cannot be printed on the ballot for more than one public office at the same election. (Certain minor exceptions exist for party precinct committeemen).', 'https://www.azleg.gov/ars/16/00344.htm', 'A.R.S. § 16-344', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates attempting to run simultaneously for multiple offices.', 'batch_2026-05-10T21-20-35_arizona_full_v1'),
  ('6a87cbef6f80d86d', 'AZ', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'How is the order of candidate names determined on the ballot?', '["Who gets the top spot on the ballot?","Ballot order drawing rules","How are names randomized on ballots?"]', 'Arizona rotates candidate names on the ballot so that each candidate appears at the top of the list in an equal number of precincts across the district, ensuring no candidate receives a permanent alphabetical advantage.', 'https://www.azleg.gov/ars/16/00464.htm', 'A.R.S. § 16-464(B)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates appearing on an Arizona ballot.', 'batch_2026-05-10T21-20-35_arizona_full_v1')
